    type: 'result',
    subtype: 'error',
    duration_ms: 50,
    duration_api_ms: 40,
    is_error: true,
    num_turns: 1,
    result: message,
    stop_reason: 'error',
    total_cost_usd: 0,
    usage: { input_tokens: 5, output_tokens: 0, cache_read_input_tokens: 0, cache_creation_input_tokens: 0 },
    modelUsage: {},
    permission_denials: [],
    session_id: SESSION_ID,
    uuid: BASE_UUID,
  };
}
```

